import json
import logging

log = logging.getLogger(__name__)


def process_records(records):
    results = []
    for record in records:
        if record['status'] != 'active' or record['value'] <= 0:
            continue
        try:
            results.append(transform(record))
        except (KeyError, ValueError, TypeError) as e:
            log.warning('Failed to transform record %s: %s', record.get('name', '?'), e)
    return results


def transform(record):
    return {
        'name': record['name'],
        'amount': float(record['value']),
        'tags': record.get('tags', []) + ['processed'],
    }


def load_config(path):
    with open(path) as f:
        return json.load(f)
